content.content:
  1→/* ═══════════════════════════════════════════════════
  2→   Profile Post Cards — Parent Container
  3→   ═══════════════════════════════════════════════════ */
  4→.profile-postcards-parent-container {
  5→    position: relative;
  6→    display: flex;
  7→    flex-direction: column;
  8→    justify-content: flex-start;
  9→    align-items: center;
 10→    width: 90%;
 11→    padding: 1.25rem;
 12→    height: fit-content;
 13→    margin-bottom: 1rem;
 14→    margin-top: 1rem;
 15→    border-radius: 18px;
 16→    background-color: var(--bg-glass);
 17→    backdrop-filter: blur(25px);
 18→    -webkit-backdrop-filter: blur(25px);
 19→    border: 0.7px solid var(--bg-glass-border);
 20→    gap: 18px;
 21→}
 22→/* ═══════════════════════════════════════════════════
 23→   Postcards Header Row
 24→   ═══════════════════════════════════════════════════ */
 25→.postcards-header-row {
 26→    display: flex;
 27→    align-items: center;
 28→    justify-content: space-between;
 29→    width: 100%;
 30→    padding: 0 0.15rem;
 31→}
 32→
 33→.postcards-heading {
 34→    margin: 0;
 35→    font-family: var(--font-ui);
 36→    font-size: 1.15rem;
 37→    font-weight: 700;
 38→    color: var(--text-heading);
 39→    letter-spacing: -0.01em;
 40→    line-height: 1;
 41→}
 42→
 43→.postcards-count {
 44→    font-weight: 600;
 45→    color: var(--text-muted);
 46→    font-size: 0.95rem;
 47→}
 48→
 49→.postcards-header-actions {
 50→    display: flex;
 51→    align-items: center;
 52→    gap: 0.35rem;
 53→}
 54→
 55→.postcards-view-toggle-btn {
 56→    display: flex;
 57→    align-items: center;
 58→    justify-content: center;
 59→    width: 34px;
 60→    height: 34px;
 61→    padding: 0;
 62→    background: transparent;
 63→    border: 1px solid var(--border-card);
 64→    border-radius: 8px;
 65→    color: var(--text-muted);
 66→    cursor: pointer;
 67→    transition: background 0.15s ease, color 0.15s ease, border-color 0.15s ease;
 68→}
 69→
 70→.postcards-view-toggle-btn:hover {
 71→    background: var(--bg-hover, rgba(0, 0, 0, 0.04));
 72→    color: var(--text-primary);
 73→    border-color: var(--text-muted);
 74→}
 75→
 76→.postcards-view-toggle-btn.is-active {
 77→    background: var(--bg-hover, rgba(0, 0, 0, 0.08));
 78→    color: var(--text-primary);
 79→    border-color: var(--text-muted);
 80→}
 81→
 82→/* ═══════════════════════════════════════════════════
 83→   Grid View
 84→   ═══════════════════════════════════════════════════ */
 85→.postcards-grid-view {
 86→    display: grid;
 87→    grid-template-columns: repeat(3, 1fr);
 88→    gap: 10px;
 89→    width: 100%;
 90→}
 91→
 92→.postcards-grid-item {
 93→    display: flex;
 94→    flex-direction: column;
 95→    overflow: visible;
 96→    cursor: pointer;
 97→    background: var(--bg-primary);
 98→    border: 1px solid var(--border-card);
 99→    border-radius: 10px;
100→    transition: box-shadow 0.2s ease, transform 0.2s ease, border-color 0.2s ease;
101→}
102→
103→.postcards-grid-item:hover {
104→    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.08);
105→    transform: translateY(-2px);
106→    border-color: rgba(0, 0, 0, 0.09);
107→}
108→
109→[data-theme="dark"] .postcards-grid-item:hover {
110→    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.25);
111→    border-color: rgba(255, 255, 255, 0.1);
112→}
113→
114→.postcards-grid-img-wrap {
115→    width: 100%;
116→    aspect-ratio: 4 / 3;
117→    overflow: hidden;
118→    flex-shrink: 0;
119→    border-top-left-radius: 10px;
120→    border-top-right-radius: 10px;
121→}
122→
123→.postcards-grid-thumb {
124→    width: 100%;
125→    height: 100%;
126→    object-fit: cover;
127→    display: block;
128→    transition: transform 0.25s ease, opacity 0.2s ease;
129→}
130→
131→.postcards-grid-item:hover .postcards-grid-thumb {
132→    transform: scale(1.04);
133→    opacity: 0.92;
134→}
135→
136→.postcards-grid-body {
137→    display: flex;
138→    flex-direction: column;
139→    gap: 0.15rem;
140→    padding: 0.5rem 0.55rem;
141→    flex: 1;
142→    min-height: 0;
143→}
144→
145→.postcards-grid-title {
146→    margin: 0;
147→    font-family: "Lexend Deca", sans-serif;
148→    font-size: 0.68rem;
149→    font-weight: 650;
150→    line-height: 1.3;
151→    color: var(--text-heading);
152→    display: -webkit-box;
153→    -webkit-line-clamp: 2;
154→    -webkit-box-orient: vertical;
155→    overflow: hidden;
156→}
157→
158→.postcards-grid-snippet {
159→    margin: 0;
160→    font-family: var(--font-serif);
161→    font-size: 0.6rem;
162→    font-weight: 400;
163→    line-height: 1.4;
164→    color: var(--text-body);
165→    opacity: 0.75;
166→    display: -webkit-box;
167→    -webkit-line-clamp: 2;
168→    -webkit-box-orient: vertical;
169→    overflow: hidden;
170→}
171→
172→/* ═══════════════════════════════════════════════════
173→   Grid Item — Footer & Settings
174→   ═══════════════════════════════════════════════════ */
175→.postcards-grid-item {
176→    position: relative;
177→}
178→
179→.postcards-grid-body-footer {
180→    display: flex;
181→    align-items: center;
182→    justify-content: space-between;
183→    margin-top: auto;
184→    padding-top: 0.3rem;
185→}
186→
187→.postcards-grid-item .user-post-settings svg {
188→    width: 20px;
189→    height: 20px;
190→}
191→
192→.postcards-grid-item .user-post-privacy {
193→    display: flex;
194→    align-items: center;
195→    color: var(--text-muted);
196→}
197→
198→.postcards-grid-item .post-settings-container {
199→    position: absolute;
200→    top: 50%;
201→    left: 50%;
202→    z-index: 20;
203→}
204→
205→.postcards-grid-item .confirmation-delete-bg {
206→    bottom: 0;
207→}
208→
209→/* ═══════════════════════════════════════════════════
210→   List View
211→   ═══════════════════════════════════════════════════ */
212→.postcards-list-view {
213→    display: flex;
214→    flex-direction: column;
215→    gap: 18px;
216→    width: 100%;
217→}
218→
219→.profile-postcards-child-container {
220→    display: flex;
221→    width: 100%;
222→    position: relative;
223→}
224→.profile-postcards-loading-container {
225→    display: flex;
226→    justify-content: center;
227→    align-items: center;
228→    width: 90%;
229→    height: 100vh;
230→    margin-top: 1rem;
231→    border-radius: 18px;
232→    padding: 1rem;
233→    background-color: var(--bg-glass);
234→    backdrop-filter: blur(25px);
235→    -webkit-backdrop-filter: blur(25px);
236→    border: 0.7px solid var(--bg-glass-border);
237→    color: var(--text-muted);
238→    font-family: "Nunito", sans-serif;
239→    font-weight: 600;
240→}
241→
242→/* ═══════════════════════════════════════════════════
243→   Individual Profile Card
244→   ═══════════════════════════════════════════════════ */
245→.profile-postcards {
246→    position: relative;
247→    display: flex;
248→    flex-direction: column;
249→    justify-content: flex-start;
250→    align-items: center;
251→    width: 100%;
252→    min-height: fit-content;
253→    background-color: var(--bg-primary);
254→    border: 1px solid var(--border-card);
255→    border-radius: 14px;
256→    overflow: visible;
257→    cursor: pointer;
258→    transition: box-shadow 0.25s ease, border-color 0.25s ease, transform 0.2s ease;
259→}
260→.profile-postcards:hover {
261→    box-shadow: 0 6px 28px rgba(0, 0, 0, 0.07), 0 1px 6px rgba(0, 0, 0, 0.04);
262→    border-color: rgba(0, 0, 0, 0.09);
263→    transform: translateY(-1px);
264→}
265→[data-theme="dark"] .profile-postcards:hover {
266→    box-shadow: 0 6px 28px rgba(0, 0, 0, 0.25), 0 1px 6px rgba(0, 0, 0, 0.15);
267→    border-color: rgba(255, 255, 255, 0.1);
268→}
269→.profile-postcards .card-image-banner {
270→    width: 100%;
271→    max-height: 240px;
272→    object-fit: cover;
273→    display: block;
274→    border-top-left-radius: 14px;
275→    border-top-right-radius: 14px;
276→    transition: opacity 0.2s ease;
277→}
278→.profile-postcards:hover .card-image-banner {
279→    opacity: 0.92;
280→}
281→
282→/* ═══════════════════════════════════════════════════
283→   Card Content Area
284→   ═══════════════════════════════════════════════════ */
285→.user-profile-card-content {
286→    display: flex;
287→    flex-direction: column;
288→    gap: 0.5rem;
289→    width: 100%;
290→    padding: 1.1rem 1.35rem 0.85rem 1.35rem;
291→    box-sizing: border-box;
292→}
293→.user-profile-card-content .card-icons-container {
294→    display: flex;
295→    flex-wrap: wrap;
296→    width: 100%;
297→    padding: 0.5rem 0 0 0;
298→    min-height: 22px;
299→    align-items: center;
300→    justify-content: flex-start;
301→    gap: 0.5rem;
302→    border-top: 1px solid var(--border-card);
303→}
304→.user-profile-card-content .content-container {
305→    display: flex;
306→    flex-direction: column;
307→    justify-content: flex-start;
308→    align-items: flex-start;
309→    user-select: none;
310→    gap: 0.4rem;
311→}
312→.user-profile-card-content .feed-text-content-container {
313→    width: 100%;
314→}
315→.user-profile-card-content .user-info-email-container {
316→    display: none;
317→}
318→
319→/* In-view loader */
320→.in-view-container {
321→    display: flex;
322→    justify-content: center;
323→    align-items: center;
324→    width: 100%;
325→    height: 20px;
326→    margin-top: 1rem;
327→}
328→
329→/* Avatar rings */
330→.user-avatar-container.avatar-ring-legend {
331→    border-radius: 50%;
332→    border: 2px solid #FFD700;
333→    box-shadow:
334→        0 0 6px 1px rgba(255, 215, 0, 0.5),
335→        0 0 12px 2px rgba(255, 215, 0, 0.35),
336→        0 0 20px 4px rgba(255, 215, 0, 0.2);
337→    animation: glow-legend 2s ease-in-out infinite alternate;
338→}
339→.user-avatar-container.avatar-ring-og {
340→    border-radius: 50%;
341→    border: 2px solid #9B59FF;
342→    box-shadow:
343→        0 0 6px 1px rgba(155, 89, 255, 0.5),
344→        0 0 12px 2px rgba(155, 89, 255, 0.35),
345→        0 0 20px 4px rgba(155, 89, 255, 0.2);
346→    animation: glow-og 2s ease-in-out infinite alternate;
347→}
348→
349→@keyframes glow-legend {
350→    from {
351→        box-shadow:
352→            0 0 6px 1px rgba(255, 215, 0, 0.5),
353→            0 0 12px 2px rgba(255, 215, 0, 0.35),
354→            0 0 20px 4px rgba(255, 215, 0, 0.2);
355→    }
356→    to {
357→        box-shadow:
358→            0 0 8px 2px rgba(255, 215, 0, 0.6),
359→            0 0 16px 4px rgba(255, 215, 0, 0.4),
360→            0 0 24px 6px rgba(255, 215, 0, 0.25);
361→    }
362→}
363→
364→@keyframes glow-og {
365→    from {
366→        box-shadow:
367→            0 0 6px 1px rgba(155, 89, 255, 0.5),
368→            0 0 12px 2px rgba(155, 89, 255, 0.35),
369→            0 0 20px 4px rgba(155, 89, 255, 0.2);
370→    }
371→    to {
372→        box-shadow:
373→            0 0 8px 2px rgba(155, 89, 255, 0.6),
374→            0 0 16px 4px rgba(155, 89, 255, 0.4),
375→            0 0 24px 6px rgba(155, 89, 255, 0.25);
376→    }
377→}
378→
379→/* Profile-specific text styles */
380→.user-newsfeed-name-profile-page {
381→    font-family: "Nunito", sans-serif;
382→    font-size: 0.8rem;
383→    font-weight: 650;
384→    letter-spacing: 0.005rem;
385→    margin: 0;
386→    padding: 0;
387→    cursor: pointer;
388→    color: var(--text-secondary);
389→    transition: color 0.15s ease;
390→}
391→.user-newsfeed-name-profile-page:hover {
392→    color: var(--text-primary);
393→}
394→.feed-title-profile-page {
395→    margin: 0;
396→    padding: 0;
397→    font-family: "Lexend Deca", sans-serif;
398→    font-size: 1.08rem;
399→    font-weight: 700;
400→    line-height: 1.4;
401→    letter-spacing: -0.025rem;
402→    color: var(--text-heading);
403→    transition: color 0.15s ease;
404→}
405→.feed-text-content-profile-page {
406→    padding: 0;
407→    margin: 0;
408→    font-family: var(--font-serif);
409→    font-weight: 400;
410→    line-height: 1.7;
411→    font-size: 0.875rem;
412→    letter-spacing: 0.008rem;
413→    color: var(--text-body);
414→}
415→
416→/* ═══════════════════════════════════════════════════
417→   Post Settings Dropdown
418→   ═══════════════════════════════════════════════════ */
419→.post-settings-container {
420→    position: absolute;
421→    left: 75px;
422→    bottom: 20px;
423→    display: flex;
424→    flex-direction: column;
425→    justify-content: flex-start;
426→    align-items: flex-start;
427→    width: 240px;
428→    height: fit-content;
429→    background-color: var(--bg-elevated);
430→    color: var(--text-primary);
431→    border-radius: 12px;
432→    border: 1px solid var(--border-light);
433→    box-shadow: var(--shadow-modal);
434→    z-index: 10;
435→    overflow: hidden;
436→}
437→.setting-buttons {
438→    display: flex;
439→    justify-content: flex-start;
440→    align-items: center;
441→    width: 100%;
442→    height: fit-content;
443→}
444→.delete-button {
445→    display: flex;
446→    justify-content: flex-start;
447→    align-items: center;
448→    width: 100%;
449→    gap: 0.7rem;
450→    font-family: "Nunito", sans-serif;
451→    font-size: 0.85rem;
452→    font-weight: 650;
453→    color: rgb(255, 68, 68);
454→    padding: 0.6rem 1rem;
455→    transition: background-color 0.12s ease;
456→}
457→.delete-button:hover {
458→    background-color: rgba(255, 68, 68, 0.06);
459→}
460→.delete-button svg {
461→    width: 20px;
462→    height: 20px;
463→    flex-shrink: 0;
464→}
465→.edit-button {
466→    display: flex;
467→    justify-content: flex-start;
468→    align-items: center;
469→    width: 100%;
470→    gap: 0.7rem;
471→    font-family: "Nunito", sans-serif;
472→    font-size: 0.85rem;
473→    font-weight: 650;
474→    color: var(--text-primary);
475→    padding: 0.6rem 1rem;
476→    transition: background-color 0.12s ease;
477→}
478→.edit-button:hover {
479→    background-color: var(--bg-hover);
480→}
481→.edit-button svg {
482→    width: 20px;
483→    height: 20px;
484→    flex-shrink: 0;
485→}
486→.edit-button svg path {
487→    stroke: var(--text-primary);
488→}
489→.only-me-bttn {
490→    display: flex;
491→    justify-content: flex-start;
492→    align-items: center;
493→    width: 100%;
494→    gap: 0.7rem;
495→    font-family: "Nunito", sans-serif;
496→    font-size: 0.85rem;
497→    font-weight: 650;
498→    color: var(--text-primary);
499→    padding: 0.6rem 1rem;
500→    transition: background-color 0.12s ease;
501→}
502→.only-me-bttn:hover {
503→    background-color: var(--bg-hover);
504→}
505→.only-me-bttn svg {
506→    width: 20px;
507→    height: 20px;
508→    flex-shrink: 0;
509→}
510→.only-me-bttn svg g,
511→.only-me-bttn svg path {
512→    fill: var(--text-primary);
513→}
514→.public-post-bttn {
515→    display: flex;
516→    justify-content: flex-start;
517→    align-items: center;
518→    width: 100%;
519→    gap: 0.7rem;
520→    font-family: "Nunito", sans-serif;
521→    font-size: 0.85rem;
522→    font-weight: 650;
523→    color: var(--text-primary);
524→    padding: 0.6rem 1rem;
525→    transition: background-color 0.12s ease;
526→}
527→.public-post-bttn:hover {
528→    background-color: var(--bg-hover);
529→}
530→.public-post-bttn svg {
531→    width: 20px;
532→    height: 20px;
533→    flex-shrink: 0;
534→}
535→.public-post-bttn svg path {
536→    fill: var(--text-primary);
537→}
538→
539→/* ═══════════════════════════════════════════════════
540→   Delete Confirmation Overlay
541→   ═══════════════════════════════════════════════════ */
542→.confirm-delete-container {
543→    width: 100%;
544→    height: 100vh;
545→    position: absolute;
546→    background-color: red;
547→}
548→.confirmation-delete-bg {
549→    display: flex;
550→    justify-content: center;
551→    align-items: center;
552→    width: 100%;
553→    height: 100%;
554→    position: absolute;
555→    z-index: 1000;
556→    bottom: 110px;
557→}
558→.confirmation-delete-container {
559→    display: flex;
560→    flex-direction: column;
561→    justify-content: space-between;
562→    padding: 1.25rem;
563→    border-radius: 14px;
564→    width: 380px;
565→    height: 110px;
566→    background-color: var(--bg-elevated);
567→    color: var(--text-primary);
568→    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.18);
569→    border: 1px solid var(--border-light);
570→}
571→.confirmation-delete-heading {
572→    display: flex;
573→    width: 100%;
574→    height: fit-content;
575→    justify-content: center;
576→    align-items: center;
577→    font-family: "Nunito", sans-serif;
578→    font-weight: 700;
579→    font-size: 0.95rem;
580→}
581→.confirm-buttons-container {
582→    display: flex;
583→    width: 100%;
584→    height: fit-content;
585→    justify-content: center;
586→    align-items: center;
587→    gap: 1.5rem;
588→}
589→.confirm-buttons-yes {
590→    height: fit-content;
591→    padding: 0.45rem 1.5rem;
592→    display: flex;
593→    justify-content: center;
594→    align-items: center;
595→    font-family: "Nunito", sans-serif;
596→    font-size: 0.85rem;
597→    font-weight: 650;
598→    color: rgb(255, 68, 68);
599→    background-color: rgba(255, 68, 68, 0.08);
600→    border: 1px solid rgba(255, 68, 68, 0.15);
601→    border-radius: 10px;
602→    cursor: pointer;
603→    user-select: none;
604→    transition: background-color 0.12s ease;
605→}
606→.confirm-buttons-yes:hover {
607→    background-color: rgba(255, 68, 68, 0.15);
608→}
609→.confirm-buttons-cancel {
610→    height: fit-content;
611→    padding: 0.45rem 1.5rem;
612→    display: flex;
613→    justify-content: center;
614→    align-items: center;
615→    font-family: "Nunito", sans-serif;
616→    font-size: 0.85rem;
617→    font-weight: 650;
618→    color: var(--bg-primary);
619→    background-color: var(--text-primary);
620→    border-radius: 10px;
621→    cursor: pointer;
622→    user-select: none;
623→    transition: opacity 0.12s ease;
624→}
625→.confirm-buttons-cancel:hover {
626→    opacity: 0.85;
627→}
628→
629→/* Delete success message */
630→.journal-is-deleted-message-container {
631→    position: absolute;
632→    background-color: var(--bg-elevated);
633→    color: var(--text-primary);
634→    z-index: 11;
635→    width: 420px;
636→    height: 140px;
637→    border-radius: 14px;
638→    display: flex;
639→    flex-direction: column;
640→    justify-content: center;
641→    align-items: center;
642→    font-family: "Nunito", sans-serif;
643→    font-weight: 700;
644→    font-size: 1.3rem;
645→    gap: 0.5rem;
646→    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.18);
647→    border: 1px solid var(--border-light);
648→}
649→.delete-journal-loader-container {
650→    position: absolute;
651→    display: flex;
652→    flex-direction: column;
653→    justify-content: center;
654→    align-items: center;
655→    width: 90%;
656→    height: 100px;
657→    background-color: var(--bg-elevated);
658→    color: var(--text-primary);
659→    z-index: 10;
660→    padding: 1rem;
661→    border-radius: 14px;
662→    font-family: "Nunito", sans-serif;
663→    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.18);
664→}
665→
666→
667→/* ═══════════════════════════════════════════════════
668→   Mobile Responsive (428px)
669→   ═══════════════════════════════════════════════════ */
670→@media (max-width: 480px) {
671→    .post-settings-container {
672→        position: absolute;
673→        left: 40px;
674→        display: flex;
675→        flex-direction: column;
676→        justify-content: flex-start;
677→        align-items: flex-start;
678→        width: 240px;
679→        height: fit-content;
680→        background-color: var(--bg-elevated);
